// MARK: - WKScriptMessageHandler

extension HybridWebViewController: WKScriptMessageHandler {
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        
        guard let handler = JSMessageHandler(rawValue: message.name) else { return }
        
        let body = message.body as? String ?? ""
        let data = parseJSON(body)
        
        switch handler {
        case .camera:
            handleCameraRequest(data: data)
        case .pushNotification:
            handlePushNotificationRequest(data: data)
        case .inAppPurchase:
            handleInAppPurchaseRequest(data: data)
        case .hapticFeedback:
            handleHapticFeedback(data: data)
        case .shareContent:
            handleShareContent(data: data)
        case .deviceInfo:
            handleDeviceInfo(data: data)
        }
    }
    
    private func parseJSON(_ string: String) -> [String: Any] {
        guard let data = string.data(using: .utf8),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            return [:]
        }
        return json
    }
    
    // MARK: - Camera Handler
    
    private func handleCameraRequest(data: [String: Any]) {
        let type = data["type"] as? String ?? "photo"
        
        AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
            DispatchQueue.main.async {
                guard granted else {
                    self?.rejectPromise(rejecter: "_cameraReject", error: "Camera permission denied")
                    self?.showPermissionAlert(for: "Camera")
                    return
                }
                
                let picker = UIImagePickerController()
                picker.delegate = self
                picker.allowsEditing = true
                
                if type == "photo" && UIImagePickerController.isSourceTypeAvailable(.camera) {
                    picker.sourceType = .camera
                    picker.cameraCaptureMode = .photo
                } else if type == "video" && UIImagePickerController.isSourceTypeAvailable(.camera) {
                    picker.sourceType = .camera
                    picker.cameraCaptureMode = .video
                    picker.videoMaximumDuration = 60
                    picker.mediaTypes = ["public.movie"]
                } else if type == "library" {
                    picker.sourceType = .photoLibrary
                } else {
                    picker.sourceType = .photoLibrary
                }
                
                self?.present(picker, animated: true)
            }
        }
    }
    
    // MARK: - Push Notification Handler
    
    private func handlePushNotificationRequest(data: [String: Any]) {
        let action = data["action"] as? String ?? ""
        
        switch action {
        case "requestPermission":
            UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
                DispatchQueue.main.async {
                    if granted {
                        UIApplication.shared.registerForRemoteNotifications()
                        self?.resolvePromise(resolver: "_pushResolve", value: "{ granted: true }")
                    } else {
                        let errorMsg = error?.localizedDescription ?? "Permission denied"
                        self?.rejectPromise(rejecter: "_pushReject", error: errorMsg)
                    }
                }
            }
            
        case "getToken":
            // Token is typically stored when received in AppDelegate
            if let token = UserDefaults.standard.string(forKey: "devicePushToken") {
                resolvePromise(resolver: "_pushTokenResolve", value: "'\(token)'")
            } else {
                rejectPromise(rejecter: "_pushTokenReject", error: "Push token not available")
            }
            
        default:
            break
        }
    }
    
    // MARK: - In-App Purchase Handler
    
    private func handleInAppPurchaseRequest(data: [String: Any]) {
        let action = data["action"] as? String ?? ""
        
        switch action {
        case "getProducts":
            if let productIds = data["productIds"] as? [String] {
                fetchProducts(productIds: Set(productIds))
            }
            
        case "purchase":
            if let productId = data["productId"] as? String {
                purchaseProduct(productId: productId)
            }
            
        case "restore":
            restorePurchases()
            
        default:
            break
        }
    }
    
    // MARK: - Haptic Feedback Handler
    
    private func handleHapticFeedback(data: [String: Any]) {
        let type = data["type"] as? String ?? "medium"
        
        switch type {
        case "light":
            let generator = UIImpactFeedbackGenerator(style: .light)
            generator.impactOccurred()
        case "medium":
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        case "heavy":
            let generator = UIImpactFeedbackGenerator(style: .heavy)
            generator.impactOccurred()
        case "success":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.success)
        case "warning":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.warning)
        case "error":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.error)
        case "selection":
            let generator = UISelectionFeedbackGenerator()
            generator.selectionChanged()
        default:
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        }
    }
    
    // MARK: - Share Content Handler
    
    private func handleShareContent(data: [String: Any]) {
        var items: [Any] = []
        
        if let title = data["title"] as? String {
            items.append(title)
        }
        if let text = data["text"] as? String {
            items.append(text)
        }
        if let urlString = data["url"] as? String, let url = URL(string: urlString) {
            items.append(url)
        }
        
        guard !items.isEmpty else { return }
        
        DispatchQueue.main.async { [weak self] in
            let activityVC = UIActivityViewController(activityItems: items, applicationActivities: nil)
            
            // For iPad
            if let popover = activityVC.popoverPresentationController {
                popover.sourceView = self?.view
                popover.sourceRect = CGRect(x: self?.view.bounds.midX ?? 0,
                                           y: self?.view.bounds.midY ?? 0,
                                           width: 0, height: 0)
            }
            
            self?.present(activityVC, animated: true)
        }
    }
    
    // MARK: - Device Info Handler
    
    private func handleDeviceInfo(data: [String: Any]) {
        let device = UIDevice.current
        let info: [String: Any] = [
            "model": device.model,
            "systemName": device.systemName,
            "systemVersion": device.systemVersion,
            "name": device.name,
            "identifierForVendor": device.identifierForVendor?.uuidString ?? "",
            "batteryLevel": device.batteryLevel,
            "isCharging": device.batteryState == .charging || device.batteryState == .full,
            "screenWidth": UIScreen.main.bounds.width,
            "screenHeight": UIScreen.main.bounds.height,
            "scale": UIScreen.main.scale,
            "appVersion": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "",
            "buildNumber": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? ""
        ]
        
        if let jsonData = try? JSONSerialization.data(withJSONObject: info),
           let jsonString = String(data: jsonData, encoding: .utf8) {
            resolvePromise(resolver: "_deviceInfoResolve", value: jsonString)
        }
    }
    
    // MARK: - Helpers
    
    private func showPermissionAlert(for feature: String) {
        let alert = UIAlertController(
            title: "\(feature) Access Required",
            message: "Please enable \(feature.lowercased()) access in Settings to use this feature.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Settings", style: .default) { _ in
            if let settingsURL = URL(string: UIApplication.openSettingsURLString) {
                UIApplication.shared.open(settingsURL)
            }
        })
        present(alert, animated: true)
    }
}

// MARK: - WKNavigationDelegate

extension HybridWebViewController: WKNavigationDelegate {
    
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        activityIndicator.startAnimating()
        progressView.isHidden = false
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
        showErrorAlert(error: error)
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
        showErrorAlert(error: error)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Handle external links (open in Safari)
        let urlString = url.absoluteString
        if let host = url.host, !host.contains("yourmobilewebsite.com") {
            // Handle special URL schemes
            if url.scheme == "tel" || url.scheme == "mailto" || url.scheme == "sms" {
                UIApplication.shared.open(url)
                decisionHandler(.cancel)
                return
            }
            
            // Open external links in Safari
            if navigationAction.navigationType == .linkActivated {
                UIApplication.shared.open(url)
                decisionHandler(.cancel)
                return
            }
        }
        
        // Handle deep links or custom URL schemes
        if url.scheme == "myapp" {
            handleDeepLink(url: url)
            decisionHandler(.cancel)
            return
        }
        
        // Handle App Store links
        if urlString.contains("itunes.apple.com") || urlString.contains("apps.apple.com") {
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationResponse: WKNavigationResponse, decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void) {
        
        if let httpResponse = navigationResponse.response as? HTTPURLResponse {
            if httpResponse.statusCode >= 400 {
                print("HTTP Error: \(httpResponse.statusCode)")
            }
        }
        
        decisionHandler(.allow)
    }
    
    private func showErrorAlert(error: Error) {
        let nsError = error as NSError
        
        // Don't show alert for cancelled requests
        guard nsError.code != NSURLErrorCancelled else { return }
        
        let alert = UIAlertController(
            title: "Connection Error",
            message: "Unable to load the page. Please check your internet connection and try again.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Retry", style: .default) { [weak self] _ in
            self?.loadWebsite()
        })
        present(alert, animated: true)
    }
    
    private func handleDeepLink(url: URL) {
        // Handle custom deep links
        let path = url.path
        let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: false)?.queryItems
        
        print("Deep link received - path: \(path), params: \(String(describing: queryItems))")
        
        // Navigate web view to appropriate page
        if let webURL = URL(string: "\(websiteURL)\(path)") {
            webView.load(URLRequest(url: webURL))
        }
    }
}

// MARK: - WKUIDelegate

extension HybridWebViewController: WKUIDelegate {
    
    // Handle JavaScript alerts
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript confirms
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript text input
    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (String?) -> Void) {
        let alert = UIAlertController(title: nil, message: prompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }
    
    // Handle new window requests (target="_blank")
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        if navigationAction.targetFrame == nil || !(navigationAction.targetFrame?.isMainFrame ?? false) {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

// MARK: - UIImagePickerControllerDelegate

extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        picker.dismiss(animated: true)
        
        if let image = info[.editedImage] as? UIImage ?? info[.originalImage] as? UIImage {
            if let imageData = image.jpegData(compressionQuality: 0.7) {
                let base64String = imageData.base64EncodedString()
                let dataURI = "data:image/jpeg;base64,\(base64String)"
                resolvePromise(resolver: "_cameraResolve", value: "{ imageData: '\(dataURI)', width: \(image.size.width), height: \(image.size.height) }")
            }
        } else if let videoURL = info[.mediaURL] as? URL {
            resolvePromise(resolver: "_cameraResolve", value: "{ videoUrl: '\(videoURL.absoluteString)' }")
        } else {
            rejectPromise(rejecter: "_cameraReject", error: "Failed to capture media")
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
        rejectPromise(rejecter: "_cameraReject", error: "User cancelled")
    }
}

// MARK: - StoreKit / In-App Purchases

extension HybridWebViewController: SKProductsRequestDelegate, SKPaymentTransactionObserver {
    
    private func fetchAvailableProducts() {
        SKPaymentQueue.default().add(self)
    }
    
    private func fetchProducts(productIds: Set<String>) {
        let request = SKProductsRequest(productIdentifiers: productIds)
        request.delegate = self
        request.start()
    }
    
    private func purchaseProduct(productId: String) {
        guard SKPaymentQueue.canMakePayments() else {
            rejectPromise(rejecter: "_purchaseReject", error: "In-app purchases are not allowed on this device")
            return
        }
        
        guard let product = products.first(where: { $0.productIdentifier == productId }) else {
            rejectPromise(rejecter: "_purchaseReject", error: "Product not found: \(productId)")
            return
        }
        
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
    
    private func restorePurchases() {
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    // SKProductsRequestDelegate
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        products = response.products
        
        let productList = products.map { product -> [String: Any] in
            return [
                "id": product.productIdentifier,
                "title": product.localizedTitle,
                "description": product.localizedDescription,
                "price": product.price.doubleValue,
                "priceLocale": product.priceLocale.currencySymbol ?? "$",
                "formattedPrice": formatPrice(product: product)
            ]
        }
        
        if let jsonData = try? JSONSerialization.data(withJSONObject: productList),
           let jsonString = String(data: jsonData, encoding: .utf8) {
            resolvePromise(resolver: "_productsResolve", value: jsonString)
        }
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        rejectPromise(rejecter: "_productsReject", error: error.localizedDescription)
    }
    
    // SKPaymentTransactionObserver
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                let receipt = getReceiptData()
                let result: [String: Any] = [
                    "productId": transaction.payment.productIdentifier,
                    "transactionId": transaction.transactionIdentifier ?? "",
                    "receipt": receipt ?? ""
                ]
                if let jsonData = try? JSONSerialization.data(withJSONObject: result),
                   let jsonString = String(data: jsonData, encoding: .utf8) {
                    resolvePromise(resolver: "_purchaseResolve", value: jsonString)
                }
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .failed:
                let errorMessage = transaction.error?.localizedDescription ?? "Purchase failed"
                rejectPromise(rejecter: "_purchaseReject", error: errorMessage)
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .restored:
                let result: [String: Any] = [
                    "productId": transaction.payment.productIdentifier,
                    "transactionId": transaction.transactionIdentifier ?? "",
                    "restored": true
                ]
                if let jsonData = try? JSONSerialization.data(withJSONObject: result),
                   let jsonString = String(data: jsonData, encoding: .utf8) {
                    callJavaScript("if(window._restoreResolve) { window._restoreResolve(\(jsonString)); }")
                }
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .deferred, .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        resolvePromise(resolver: "_restoreResolve", value: "{ success: true }")
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        rejectPromise(rejecter: "_restoreReject", error: error.localizedDescription)
    }
    
    private func formatPrice(product: SKProduct) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.locale = product.priceLocale
        return formatter.string(from: product.price) ?? "\(product.price)"
    }
    
    private func getReceiptData() -> String? {
        guard let receiptURL = Bundle.main.appStoreReceiptURL,
              let receiptData = try? Data(contentsOf: receiptURL) else {
            return nil
        }
        return receiptData.base64EncodedString()
    }
}

// MARK: - LeakAvoider (Prevents WKWebView retain cycle)

class LeakAvoider: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

// MARK: - SceneDelegate / AppDelegate Integration Helper

extension HybridWebViewController {
    
    /// Call this from AppDelegate when push token is received
    static func savePushToken(_ token: String) {
        UserDefaults.standard.set(token, forKey: "devicePushToken")
    }
    
    /// Call this to send a message to the web content
    func sendMessageToWeb(event: String, data: [String: Any]) {
        if let jsonData = try? JSONSerialization.data(withJSONObject: data),
           let jsonString = String(data: jsonData, encoding: .utf8) {
            let script = """
            document.dispatchEvent(new CustomEvent('\(event)', { detail: \(jsonString) }));
            """
            callJavaScript(script)
        }
    }
    
    /// Handle universal links
    func handleUniversalLink(_ url: URL) {
        if let webURL = URL(string: "\(websiteURL)\(url.path)") {
            webView.load(URLRequest(url: webURL))
        }
    }
}

// MARK: - Pull to Refresh

extension HybridWebViewController {
    
    func setupPullToRefresh() {
        let refreshControl = UIRefreshControl()
        refreshControl.addTarget(self, action: #selector(handlePullToRefresh(_:)), for: .valueChanged)
        webView.scrollView.refreshControl = refreshControl
    }
    
    @objc private func handlePullToRefresh(_ sender: UIRefreshControl) {
        webView.reload()
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) {
            sender.endRefreshing()
        }
    }
}

